import{_ as e,c as o,o as a,ag as l}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Conditional Logic","description":"","frontmatter":{},"headers":[],"relativePath":"conditional-logic.md","filePath":"conditional-logic.md","lastUpdated":1777120286000}'),n={name:"conditional-logic.md"};function i(r,t,s,d,h,g){return a(),o("div",null,t[0]||(t[0]=[l('<h1 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h1><p><strong>Conditional Logic</strong> allows you to dynamically show or hide fields based on the value of other fields in the same group. This creates a personalized, step-by-step experience for your customers — they only see the options that are relevant to their current selections.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Each field in an Option Group has a <strong>Conditional Logic</strong> section at the bottom of its settings panel. When you enable it, you define one or more <strong>rules</strong> that determine whether the field is visible or hidden.</p><h3 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Concept</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Action</strong></td><td style="text-align:left;">Choose whether to <strong>Show</strong> or <strong>Hide</strong> this field when the rules are met.</td></tr><tr><td style="text-align:left;"><strong>Match Mode</strong></td><td style="text-align:left;">Choose <strong>ALL</strong> (every rule must be true) or <strong>ANY</strong> (at least one rule must be true).</td></tr><tr><td style="text-align:left;"><strong>Rules</strong></td><td style="text-align:left;">One or more conditions that reference other fields in the same group.</td></tr></tbody></table><h2 id="rule-components" tabindex="-1">Rule Components <a class="header-anchor" href="#rule-components" aria-label="Permalink to &quot;Rule Components&quot;">​</a></h2><p>A rule consists of three parts:</p><ul><li><strong>Target Field:</strong> The other field you want to &quot;watch&quot; for changes.</li><li><strong>Operator:</strong> The comparison type. Supported operators include: <ul><li><strong>equals:</strong> Matches the value exactly.</li><li><strong>not equals:</strong> Matches anything except the value.</li><li><strong>greater than:</strong> (For numbers) Checks if the input is larger.</li><li><strong>less than:</strong> (For numbers) Checks if the input is smaller.</li><li><strong>greater than or equals:</strong> (For numbers) Checks if the input is larger or equal.</li><li><strong>less than or equals:</strong> (For numbers) Checks if the input is smaller or equal.</li><li><strong>contains:</strong> Checks if the value exists within the input (useful for text or multi-select).</li><li><strong>not contains:</strong> Checks if the value is missing from the input.</li><li><strong>is empty:</strong> Triggers if the field has no value.</li><li><strong>is not empty:</strong> Triggers if the field has any value.</li></ul></li><li><strong>Value:</strong> The specific value that triggers the logic.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The available operators change depending on the <strong>type</strong> of the target field. Number fields get mathematical operators (<code>&gt;</code>, <code>&lt;</code>, <code>&gt;=</code>, <code>&lt;=</code>), while text and select fields get string operators (<code>contains</code>, <code>not contains</code>).</p></div><h2 id="operator-availability-by-field-type" tabindex="-1">Operator Availability by Field Type <a class="header-anchor" href="#operator-availability-by-field-type" aria-label="Permalink to &quot;Operator Availability by Field Type&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Target Field Type</th><th style="text-align:left;">Available Operators</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Text / Textarea</strong></td><td style="text-align:left;">equals, not equals, contains, not contains, is empty, is not empty</td></tr><tr><td style="text-align:left;"><strong>Number</strong></td><td style="text-align:left;">equals, not equals, greater than, less than, greater than or equals, less than or equals, is empty, is not empty</td></tr><tr><td style="text-align:left;"><strong>Select / Radio / Checkbox</strong></td><td style="text-align:left;">equals, not equals, contains, not contains, is empty, is not empty</td></tr><tr><td style="text-align:left;"><strong>Single Checkbox</strong></td><td style="text-align:left;">equals, not equals, is empty, is not empty</td></tr></tbody></table><h2 id="practical-examples" tabindex="-1">Practical Examples <a class="header-anchor" href="#practical-examples" aria-label="Permalink to &quot;Practical Examples&quot;">​</a></h2><h3 id="example-1-show-a-text-field-based-on-a-checkbox" tabindex="-1">Example 1: Show a Text Field Based on a Checkbox <a class="header-anchor" href="#example-1-show-a-text-field-based-on-a-checkbox" aria-label="Permalink to &quot;Example 1: Show a Text Field Based on a Checkbox&quot;">​</a></h3><p><strong>Scenario:</strong> You want to show an &quot;Engraving Text&quot; input only when the customer checks &quot;Add Engraving?&quot;</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;">Action</td><td style="text-align:left;"><strong>Show</strong></td></tr><tr><td style="text-align:left;">Match</td><td style="text-align:left;"><strong>ALL</strong></td></tr><tr><td style="text-align:left;">Target Field</td><td style="text-align:left;">&quot;Add Engraving?&quot; (single_checkbox)</td></tr><tr><td style="text-align:left;">Operator</td><td style="text-align:left;"><strong>equals</strong></td></tr><tr><td style="text-align:left;">Value</td><td style="text-align:left;"><code>1</code></td></tr></tbody></table><h3 id="example-2-hide-a-field-based-on-a-dropdown-selection" tabindex="-1">Example 2: Hide a Field Based on a Dropdown Selection <a class="header-anchor" href="#example-2-hide-a-field-based-on-a-dropdown-selection" aria-label="Permalink to &quot;Example 2: Hide a Field Based on a Dropdown Selection&quot;">​</a></h3><p><strong>Scenario:</strong> You want to hide a &quot;Custom Size&quot; number field when the customer selects &quot;Standard&quot; from a size dropdown.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;">Action</td><td style="text-align:left;"><strong>Hide</strong></td></tr><tr><td style="text-align:left;">Match</td><td style="text-align:left;"><strong>ALL</strong></td></tr><tr><td style="text-align:left;">Target Field</td><td style="text-align:left;">&quot;Size&quot; (select)</td></tr><tr><td style="text-align:left;">Operator</td><td style="text-align:left;"><strong>equals</strong></td></tr><tr><td style="text-align:left;">Value</td><td style="text-align:left;"><code>standard</code></td></tr></tbody></table><h3 id="example-3-show-a-field-when-any-of-multiple-conditions-are-met" tabindex="-1">Example 3: Show a Field When ANY of Multiple Conditions Are Met <a class="header-anchor" href="#example-3-show-a-field-when-any-of-multiple-conditions-are-met" aria-label="Permalink to &quot;Example 3: Show a Field When ANY of Multiple Conditions Are Met&quot;">​</a></h3><p><strong>Scenario:</strong> You want to show a &quot;Special Instructions&quot; textarea when the customer selects either &quot;Custom&quot; from a type dropdown OR enters a number greater than 10 in a quantity field.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;">Action</td><td style="text-align:left;"><strong>Show</strong></td></tr><tr><td style="text-align:left;">Match</td><td style="text-align:left;"><strong>ANY</strong></td></tr><tr><td style="text-align:left;">Rule 1</td><td style="text-align:left;">Target: &quot;Type&quot; → Operator: <strong>equals</strong> → Value: <code>custom</code></td></tr><tr><td style="text-align:left;">Rule 2</td><td style="text-align:left;">Target: &quot;Quantity&quot; → Operator: <strong>greater than</strong> → Value: <code>10</code></td></tr></tbody></table><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Conditional logic only works between fields <strong>within the same Option Group</strong>. You cannot create rules that reference fields from a different group.</p></div><ul><li><strong>Frontend Behavior:</strong> Conditions are evaluated instantly in the browser using JavaScript. There is no page reload — fields appear and disappear smoothly as the customer interacts with the form.</li><li><strong>Hidden Field Values:</strong> When a field is hidden by conditional logic, its value is <strong>not submitted</strong> with the form. This means hidden fields do not affect pricing or validation.</li><li><strong>Multiple Rules:</strong> You can add as many rules as you need by clicking the <strong>+ Add Rule</strong> button.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./frontend-display.html">Learn about Frontend Display</a></li><li><a href="./builder.html">Explore Field Types</a></li></ul>',27)]))}const p=e(n,[["render",i]]);export{u as __pageData,p as default};
